const fs = require("fs");
const { execFileSync } = require("child_process");

const out = "terraform/worker.js";

execFileSync(
  "npx",
  [
    "wrangler",
    "deploy",
    "src/standalone.ts",
    "--name",
    "r2-serve-standalone",
    "--compatibility-date",
    "2026-05-03",
    "--compatibility-flag",
    "nodejs_compat",
    "--dry-run",
    "--outfile",
    out,
  ],
  { stdio: "inherit" },
);

let bundle = fs.readFileSync(out, "utf8");
const multipart = bundle.match(
  /Content-Type: application\/javascript\+module\r?\n\r?\n([\s\S]*?)\r?\n------formdata-/,
);
if (multipart) bundle = multipart[1];

bundle = bundle.replace(/\n?\/\/# sourceMappingURL=.*\n?$/, "\n");
bundle = "// Code generated by `npm run build:standalone`; DO NOT EDIT.\n" + bundle;

fs.writeFileSync(out, bundle);
